/**
 * Settings Router Component
 * 
 * Main settings page router that determines user type and renders the
 * appropriate settings component (Individual or Business). Handles
 * authentication verification and user type detection.
 */

import React, { useEffect, useState } from 'react';
import { useNavigate, useLocation, Outlet, Navigate } from 'react-router-dom';
import { tokenService } from '@/features/auth/services/tokenService.js';
import logger from '@/shared/utils/logger.js';

const Settings = () => {
  const [userType, setUserType] = useState(null);
  const [loading, setLoading] = useState(true);
  const [authError, setAuthError] = useState('');
  const navigate = useNavigate();
  const location = useLocation();

  useEffect(() => {
    let redirectTimer = null;
    
    const checkAuth = () => {
      const isAuthenticated = localStorage.getItem('isAuthenticated');
      const token = tokenService.getToken();

      if (isAuthenticated !== 'true') {
        setAuthError('Authentication required. Please log in again.');
        redirectTimer = setTimeout(() => navigate('/login'), 2000);
        return;
      }

      const userDataString = localStorage.getItem('userData');

      if (userDataString) {
        try {
          const userData = JSON.parse(userDataString);
          const detectedType = userData.userType || userData.user_type || userData.usertype || 'individual';
          const userType = String(detectedType).toLowerCase();
          const normalizedType = userType === 'business' ? 'business_contact' : userType;
          setUserType(normalizedType);
        } catch (error) {
          logger.error('Settings: Error parsing user data', { error });
          setUserType('individual'); // Default to individual
        }
      } else {
        setUserType('individual'); // Default to individual
      }

      setLoading(false);
    };

    // Small delay to ensure login data is stored
    const authTimer = setTimeout(checkAuth, 100);
    
    return () => {
      clearTimeout(authTimer);
      if (redirectTimer) {
        clearTimeout(redirectTimer);
      }
    };
  }, [navigate]);

  // Redirect to the appropriate settings based on user type
  useEffect(() => {
    if (!loading && userType) {
      const isBusiness = userType === 'business' || userType === 'business_contact';
      const currentPath = location.pathname;

      logger.debug('Settings redirect check', {
        currentPath,
        userType,
        isBusiness,
        loading
      });

      // If we're at the base settings path, redirect to the appropriate settings
      if (currentPath === '/settings' || currentPath === '/settings/') {
        const targetPath = isBusiness ? '/settings/business' : '/settings/individual';
        logger.debug('Redirecting from settings base path', { from: currentPath, to: targetPath });
        navigate(targetPath, { replace: true });
      }
    }
  }, [userType, loading, navigate, location.pathname]);

  if (loading) {
    return (
      <div style={{
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        height: '400px',
        fontSize: '1.1rem',
        color: '#6b7280'
      }}>
        Loading settings...
      </div>
    );
  }

  if (authError) {
    return (
      <div style={{
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        alignItems: 'center',
        height: '400px',
        fontSize: '1.1rem',
        color: '#ef4444',
        textAlign: 'center'
      }}>
        <div style={{ marginBottom: '16px' }}>
          <span className="material-symbols-outlined" style={{ fontSize: '48px', color: '#ef4444' }}>
            error
          </span>
        </div>
        <div>{authError}</div>
        <div style={{ marginTop: '8px', fontSize: '0.9rem', color: '#6b7280' }}>
          Redirecting to login...
        </div>
      </div>
    );
  }

  // If we're at the base /settings path, we need to redirect
  // Check if we're at the exact /settings path (not a sub-route)
  const isBaseSettingsPath = location.pathname === '/settings' || location.pathname === '/settings/';

  // If we're at base path and userType is determined, use Navigate component for immediate redirect
  if (!loading && userType && isBaseSettingsPath) {
    const isBusiness = userType === 'business' || userType === 'business_contact';
    const targetPath = isBusiness ? '/settings/business' : '/settings/individual';
    logger.debug('Using Navigate component to redirect', { from: location.pathname, to: targetPath });
    return <Navigate to={targetPath} replace />;
  }

  // If still loading and at base path, show loading
  if (loading && isBaseSettingsPath) {
    return (
      <div style={{
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        height: '400px',
        fontSize: '1.1rem',
        color: '#6b7280'
      }}>
        Loading settings...
      </div>
    );
  }

  // Render the nested routes using Outlet
  // React Router will handle rendering IndividualSettings or BusinessSettings based on the route
  return <Outlet />;
};

export default Settings;
